class Solution:
    def findMedianSortedArrays(self, nums1, nums2):
        A, B = nums1, nums2
        if len(A) > len(B):
            A, B = B, A
        m, n = len(A), len(B)
        total = m + n
        half = (total + 1) // 2
        lo, hi = 0, m
        INF = float('inf')
        while lo <= hi:
            i = (lo + hi) // 2
            j = half - i
            aL = A[i - 1] if i > 0 else -INF
            aR = A[i] if i < m else INF
            bL = B[j - 1] if j > 0 else -INF
            bR = B[j] if j < n else INF
            if aL <= bR and bL <= aR:
                if total % 2 == 1:
                    return float(max(aL, bL))
                return (max(aL, bL) + min(aR, bR)) / 2.0
            elif aL > bR:
                hi = i - 1
            else:
                lo = i + 1
        return 0.0

